import { Sidebar } from '../../components/Sidebar';

import { Badge, ComplaintCard, VendorComplaintModal } from '../../components/ComplaintCard';

import { KPI, ProgressBar, NotifBanner } from '../../components/UI';

import LiveMap from '../../components/LiveMap';

import { timeAgo, calcResolutionRate, avgResolutionTime } from '../../utils/helpers';



const BTN = ({ children, onClick, color='#1565C0', outline=false, small=false }) => (

  <button onClick={onClick} style={{

    padding: small?'6px 12px':'8px 15px', borderRadius:9, fontSize:small?12:13, fontWeight:600, cursor:'pointer',

    background: outline?'#fff':color, color:outline?color:'#fff',

    border: outline?`1px solid ${color}`:'none', transition:'all .15s',

    display:'inline-flex', alignItems:'center', gap:5,

  }}>{children}</button>

);



function TaskInbox({ tasks, onAction, onSelect, onOpenAssignModal }) {

  const active = tasks.filter(c => !['COMPLETED','REJECTED'].includes(c.status));

  return (

    <>

      <div className="page-hd">

        <div className="page-title">My Tasks Workspace</div>

        <div className="page-sub">Nagpur Junction (Live Nodes) · {new Date().toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long'})}</div>

      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(110px,1fr))',gap:10,marginBottom:16}}>

        <KPI label="Total"  value={tasks.length} />

        <KPI label="New"    value={tasks.filter(c=>c.status==='NEW').length}         color="#E65100" />

        <KPI label="Active" value={tasks.filter(c=>['ACCEPTED','ASSIGNED_TO_CLEANER','CLEANED_BY_FORCE'].includes(c.status)).length} color="#1565C0" />

        <KPI label="Done"   value={tasks.filter(c=>c.status==='COMPLETED').length}   color="#2E7D32" />

      </div>

      {active.length===0

        ? <div style={{background:'#fff',border:'1px solid #DDE3E9',borderRadius:14,padding:36,textAlign:'center',color:'#7A8FA6'}}>🎉 Perfect! No pending cleaning tracks.</div>

        : <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>

            {active.map(c => (

              <ComplaintCard key={c.id} complaint={c} onClick={() => onSelect(c)} actions={

                <div style={{ display: 'flex', flexDirection: 'column', gap: 6, width: '100%' }}>

                  

                  {/* Step 1: Pehle sirf Accept ka option aayega */}

                  {c.status==='NEW' && (

                    <BTN onClick={e=>{e.stopPropagation(); onAction(c.id,'ACCEPTED')}} color="#1565C0">Accept</BTN>

                  )}

                  

                  {/* Step 2: Accept hone ke baad 'Assign Cleaner' aayega */}

                  {c.status==='ACCEPTED' && (

                    <BTN onClick={e=>{e.stopPropagation(); onOpenAssignModal(c)}} color="#4527A0">Assign Cleaner</BTN>

                  )}



                  {/* Step 3: Cleaner ke working status status block indicator */}

                  {c.status==='ASSIGNED_TO_CLEANER' && (

                    <div style={{fontSize:11, color:'#e65100', fontWeight:700, background:'#fff3e0', padding:6, borderRadius:6, textAlign:'center'}}>

                      🦺 Cleaner Working: {c.assignedTo || 'On Duty'}

                    </div>

                  )}



                  {/* Step 4: Cleaner jab kaam complete karke image click karega tab vendor ke paas aayega Complete button aur photo preview */}

                  {c.status==='CLEANED_BY_FORCE' && (

                    <div style={{ background: '#e8f5e9', padding: 8, borderRadius: 8, border: '1px solid #2e7d32' }}>

                      <div style={{ fontSize: 10, fontWeight: 700, color: '#2e7d32', marginBottom: 4 }}>📸 Cleaner Proof Image:</div>

                      {c.cleanerPhoto && <img src={c.cleanerPhoto} alt="Proof" style={{ width: '100%', height: 80, objectFit: 'cover', borderRadius: 6, marginBottom: 6 }} />}

                      <BTN onClick={e=>{e.stopPropagation(); onAction(c.id,'COMPLETED')}} color="#2E7D32">✓ Complete Task</BTN>

                    </div>

                  )}



                  <BTN onClick={e=>{e.stopPropagation(); onSelect(c)}} outline color="#546E7A" small>View Popup</BTN>

                </div>

              }/>

            ))}

          </div>

      }

    </>

  );

}


function TaskMap({ tasks, onSelect }) {
  const active = tasks.filter(c => c.lat && c.lng);
  return (
    <>
      <div className="page-hd"><div className="page-title">Live Node GIS Map</div><div className="page-sub">Real-time GPS parameters</div></div>
      <LiveMap complaints={active} height="320px" onPinClick={onSelect} />
      <div style={{marginTop:14,display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:12}}>
        {active.slice(0,4).map(c=>(
          <div key={c.id} onClick={()=>onSelect(c)} style={{display:'flex',gap:10,background:'#fff',border:'1px solid #DDE3E9',borderRadius:12,padding:'11px 13px',cursor:'pointer',alignItems:'center'}}>
            <span style={{fontSize:24}}>{c.emoji}</span>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:13,fontWeight:700}}>{c.area} — {c.gtype}</div>
              <div style={{fontSize:11,color:'#7A8FA6'}}>📍 {c.station?.name} · {timeAgo(c.reportedAt)}</div>
            </div>
            <Badge status={c.status}/>
          </div>
        ))}
      </div>
    </>
  );
}

function VendorStats({ tasks }) {
  const rate = calcResolutionRate(tasks);
  const avg  = avgResolutionTime(tasks);
  return (
    <>
      <div className="page-hd"><div className="page-title">Performance Diagnostics</div><div className="page-sub">Live SLA Analytics</div></div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>
        <div style={{background:'#fff',border:'1px solid #DDE3E9',borderRadius:14,padding:18}}>
          <div style={{fontWeight:700,fontSize:14,marginBottom:14}}>Resolution efficiency</div>
          <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:12}}>
            <div style={{width:70,height:70,borderRadius:'50%',background:`conic-gradient(#2E7D32 0% ${rate}%,#ECEFF1 ${rate}% 100%)`,position:'relative',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:800}}>{rate}%</div>
            <div>
              <div style={{fontSize:12,color:'#7A8FA6'}}>Avg Speed Latency</div>
              <div style={{fontWeight:700}}>{avg} Minutes</div>
            </div>
          </div>
          <ProgressBar value={rate} color="#2E7D32" height={6} />
        </div>
      </div>
    </>
  );
}

export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  const [tab, setTab] = useState('tasks');
  const [selected, setSelected] = useState(null);
  const [notif, setNotif] = useState(null);

  // Firestore Live State se reference track karke current container modal sync karein


  const act = async (id, status) => {
    await updateComplaint(id, { status });
    const msgs = { ACCEPTED:'Task locked into schedule', IN_PROGRESS:'Cleaner team dispatched to site', COMPLETED:'Cleared registry database!', QUERIED:'Query logged to Station Head' };
    setNotif(msgs[status] || 'State mutated successfully');
  };
  const navItems = [

    { key:'tasks', icon:'📋', label:'Tasks', count: complaints.filter(c=>c.status==='NEW').length },

    { key:'map',   icon:'🗺️', label:'Task Map' },

    { key:'done',  icon:'✅', label:'Completed History' },

    { key:'stats', icon:'📊', label:'Analytics' },

  ];

  const currentSelected = complaints.find(c => c.id === selected?.id) || selected;
  return (

    <div style={{display:'flex',height:'100vh',fontFamily:'system-ui,sans-serif',overflow:'hidden'}}>

      <Sidebar title="Express Travel" subtitle="Vendor Engine" navItems={navItems} activeTab={tab} onTabChange={setTab}

        footerUser={{initials:'RK',name:'Rajesh Kumar',role:'Vendor Head',avatarColor:'#1565C0'}}/>

      <div style={{flex:1,overflowY:'auto',background:'#F7F9FC'}}>

        {notif && <NotifBanner msg={notif} type="green" onDone={()=>setNotif(null)}/>}

        <div style={{padding:22,maxWidth:900,margin:'0 auto'}}>

          {tab==='tasks' && <TaskInbox tasks={complaints} onAction={act} onSelect={setSelected} onOpenAssignModal={setAssignModalTask}/>}

          {tab==='map'   && <TaskMap   tasks={complaints} onSelect={setSelected}/>}

          {tab==='done'  && (

            <>

              <div className="page-hd"><div className="page-title">Archive logs</div></div>

              <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>

                {complaints.filter(c=>c.status==='COMPLETED').map(c=><ComplaintCard key={c.id} complaint={c} onClick={()=>setSelected(c)}/>)}

              </div>

            </>

          )}

          {tab==='stats' && <VendorStats tasks={complaints}/>}

        </div>

      </div>

      

      {/* Mini Assignment Dropdown list overlay box */}

      {assignModalTask && (

        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999}}>

          <div style={{background:'#fff',padding:20,borderRadius:12,width:280,boxShadow:'0 4px 20px rgba(0,0,0,0.15)'}}>

            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:'#0A1628'}}>Select Cleaner Personnel</div>

            <div style={{display:'flex',flexDirection:'column',gap:8}}>

              {cleanerStaff.map(c => (

                <button key={c.id} onClick={() => handleAssignCleaner(c.name)} style={{padding:10,background:'#f7f9fc',border:'1px solid #dde3e9',borderRadius:8,cursor:'pointer',textAlign:'left',fontWeight:600}}>

                  🦺 {c.name}

                </button>

              ))}

            </div>

            <button onClick={() => setAssignModalTask(null)} style={{marginTop:12,width:'100%',padding:6,background:'#ECEFF1',border:'none',borderRadius:6,fontWeight:600,cursor:'pointer',fontSize:12}}>Cancel</button>

          </div>

        </div>

      )}



      {selected && <VendorComplaintModal complaint={currentSelected} onClose={()=>setSelected(null)} onAction={(id,s)=>act(id,s)}/>}

    </div>

  );

}
